-export function validateToonMachineView(data: unknown): ValidationResult<ToonMachineView> {
-  if (data === null || data === undefined) {
-    return {
-      valid: false,
-      errors: [
-        {
-          path: 'root',
-          message: `Data is ${data === null ? 'null' : 'undefined'}. Expected a TOON object.`,
-        },
-      ],
